// Built-in food database for the Fitness mini-app. Curated, offline, no API.
// Values are per listed serving (approximate, rounded — good enough for
// day-to-day logging). Indian staples first-class alongside global basics.

export interface FoodItem {
  id: string;
  name: string;
  /** human serving label, e.g. "1 roti", "100 g", "1 cup" */
  serving: string;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
  /** grams of dietary fibre per serving (estimated) */
  fiber?: number;
  /** grams of sugar per serving (estimated) */
  sugar?: number;
  /** milligrams of sodium per serving (estimated) */
  sodium?: number;
  tags?: string[];
}

export type FoodGroupId = 'quick' | 'indian' | 'protein' | 'seafood' | 'veg' | 'breakfast' | 'snacks' | 'brands' | 'drinks' | 'fruit' | 'global';

